  const targetPath = runtimeSessionPathRef.current

  // Update ref immediately so handleEvent stops filtering right away
  // (isSoftSwitched state is derived from viewSessionPath/runtimeSessionPath)
  isSoftSwitchedRef.current = false

  type ApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
  let piMessages: unknown[]
  try {
    piMessages = await (window.api as ApiWithMessages).getMessages()
  } catch {
    piMessages = []
  }

  const chatMessages = Array.isArray(piMessages) && piMessages.length > 0
    ? convertPiMessagesToChatMessages(piMessages)
    : []

  const lastAssistant = chatMessages.findLast(m => m.role === 'assistant')
  if (lastAssistant) {
    currentAssistantId.current = lastAssistant.id
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
    lastAssistant.blocks.forEach((block, i) => {
      currentContentBlocks.current.set(i, block)
    })
  } else {
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }

  backgroundEventBuffer.current = []

  // Sync runtimeSessionId after switching back
  type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
  try {
    const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
    if (state.sessionId) {
      setRuntimeSessionId(state.sessionId)
    }
    // Update streaming state from runtime (agent may have ended while we were away)
    updateStreamingState(state.isStreaming)
  } catch {
    // Best effort
  }

  setMessages(chatMessages)

