const enterSoftSwitch = useCallback(async (targetPath: string) => {
  type ApiWithSoftPeek = typeof window.api & { softPeek: (path: string) => Promise<{ messages: unknown[]; sessionId: string }> }
  const api = window.api as ApiWithSoftPeek

  let piMessages: unknown[]
  try {
    const result = await api.softPeek(targetPath)
    piMessages = result.messages
  } catch {
    piMessages = []
  }

  const chatMessages = convertPiMessagesToChatMessages(piMessages)

  // Update ref immediately so handleEvent starts filtering right away
  // (isSoftSwitched state is derived from viewSessionPath/runtimeSessionPath)
  isSoftSwitchedRef.current = true
  setViewSessionPath(targetPath)
  setMessages(chatMessages)
}, [])

const exitSoftSwitch = useCallback(async () => {
  const targetPath = runtimeSessionPathRef.current

  // Update ref immediately so handleEvent stops filtering right away
  // (isSoftSwitched state is derived from viewSessionPath/runtimeSessionPath)
  isSoftSwitchedRef.current = false

  type ApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
  let piMessages: unknown[]
  try {
    piMessages = await (window.api as ApiWithMessages).getMessages()
  } catch {
    piMessages = []
  }

  const chatMessages = Array.isArray(piMessages) && piMessages.length > 0
    ? convertPiMessagesToChatMessages(piMessages)
    : []

  const lastAssistant = chatMessages.findLast(m => m.role === 'assistant')
  if (lastAssistant) {
    currentAssistantId.current = lastAssistant.id
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
    lastAssistant.blocks.forEach((block, i) => {
      currentContentBlocks.current.set(i, block)
    })
  } else {
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }

  backgroundEventBuffer.current = []

  // Sync runtimeSessionId after switching back
  type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
  try {
    const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
    if (state.sessionId) {
      setRuntimeSessionId(state.sessionId)
    }
    // Update streaming state from runtime (agent may have ended while we were away)
    updateStreamingState(state.isStreaming)
  } catch {
    // Best effort
  }

  setMessages(chatMessages)
  setViewSessionPath(targetPath)
  setSoftSwitchBackgroundAgentEnded(false)

  viewSessionPathRef.current = targetPath

  pendingToolCallArgs.current.clear()
}

backgroundEventBuffer.current = []

// Sync runtimeSessionId after switching back
type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
try {
  const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
  if (state.sessionId) {
    setRuntimeSessionId(state.sessionId)
  }
  // Update streaming state from runtime (agent may have ended while we were away)
  updateStreamingState(state.isStreaming)
} catch {
  // Best effort
}

setMessages(chatMessages)
setViewSessionPath(targetPath)
setSoftSwitchBackgroundAgentEnded(false)

viewSessionPathRef.current = targetPath

import { useState, useEffect, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type {
  AgentSessionEvent,
  MessageUpdateEvent,
  ToolExecutionEndEvent,
  PiImageContent,
  PiUserMessage,
  PiAssistantMessage,
  PiToolResultMessage,
  PiContentBlock,
} from '../types/pi-events'
import type { ForkPoint } from '../types/session'

export interface TokenUsage {
  inputTokens: number
  outputTokens: number
  cacheReadTokens: number
  cacheWriteTokens: number
  totalTokens: number
  totalCost: number
  contextWindowSize: number
}

function inferContextWindow(model: string): number {
  if (!model) return 200000
  const m = model.toLowerCase()
  if (m.includes('gpt-4o') || m.includes('gpt-4-turbo')) return 128000
  if (m.includes('claude')) return 200000
  return 200000
}

interface UsePiRpcReturn {
  messages: ChatMessage[]
  isConnected: boolean
  isStreaming: boolean
  streamingMessageId: string | null
  sendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  abort: () => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  clearMessages: () => void
  loadHistory: () => Promise<void>
  syncStreamingState: () => Promise<void>
  forkPoints: ForkPoint[]
  loadForkPoints: (sessionPath: string) => Promise<void>
  onAgentEnd: (() => void) | null
  setOnAgentEnd: (cb: (() => void) | null) => void
  tokenUsage: TokenUsage
  viewSessionPath: string | null
  runtimeSessionPath: string | null
  isSoftSwitched: boolean
  enterSoftSwitch: (targetPath: string) => Promise<void>
  exitSoftSwitch: () => void
  hardSwitchToViewSession: () => Promise<void>
  setViewSessionPath: (path: string | null) => void
  setRuntimeSessionPath: (path: string | null) => void
  setRuntimeSessionId: (id: string | null) => void
  softSwitchBackgroundAgentEnded: boolean
}

function convertPiMessagesToChatMessages(piMessages: unknown[]): ChatMessage[] {
  const chatMessages: ChatMessage[] = []

  for (const raw of piMessages) {
    const msg = raw as Record<string, unknown>
    const piEntryId = typeof msg.id === 'string' ? msg.id : undefined
    if (msg.role === 'user') {
      const content = typeof msg.content === 'string'
        ? msg.content
        : Array.isArray(msg.content)
          ? (msg.content as PiContentBlock[])
              .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
              .map((c) => c.text)
              .join('')
          : ''
      chatMessages.push({
        id: crypto.randomUUID(),
        role: 'user',
        blocks: [{ type: 'text', content }],
        timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
        piEntryId,
      })
    } else if (msg.role === 'assistant') {
      const blocks: ContentBlock[] = []
      const content = msg.content as PiContentBlock[]
      if (Array.isArray(content)) {
        for (const c of content) {
          if (c.type === 'text') {
            blocks.push({ type: 'text', content: c.text })
          } else if (c.type === 'thinking') {
            blocks.push({ type: 'text', content: '\u{1F4AD} ' + c.thinking })
          } else if (c.type === 'toolCall') {
            blocks.push({
              type: 'tool_call',
              toolName: c.name,
              args: c.arguments,
              status: 'completed',
            })
          }
        }
      }
      chatMessages.push({
        id: crypto.randomUUID(),
        role: 'assistant',
        blocks,
        timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
        piEntryId,
      })
    } else if (msg.role === 'toolResult') {
      const lastAssistant = chatMessages.findLast((m) => m.role === 'assistant')
      if (lastAssistant) {
        const content = msg.content as PiContentBlock[]
        if (Array.isArray(content)) {
          for (const c of content) {
            if (c.type === 'text') {
              lastAssistant.blocks.push({ type: 'text', content: c.text })
            } else if (c.type === 'image') {
              const img = c as PiImageContent
              lastAssistant.blocks.push({
                type: 'image',
                src: `data:${img.mimeType};base64,${img.data}`,
                alt: `Result from ${msg.toolName as string}`,
              })
            }
          }
        }
      }
    }
  }

  return chatMessages
}

export function usePiRpc(): UsePiRpcReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const [isStreaming, setIsStreaming] = useState(false)
  const isStreamingRef = useRef(false)
  const lastStreamingActivityRef = useRef<number>(Date.now())
  const STREAMING_TIMEOUT_MS = 120_000 // 2 minutes safety timeout
  const [pendingUiRequests, setPendingUiRequests] = useState<Array<{ id: string; method: string; [key: string]: unknown }>>([])
  const [tokenUsage, setTokenUsage] = useState<TokenUsage>({
    inputTokens: 0,
    outputTokens: 0,
    cacheReadTokens: 0,
    cacheWriteTokens: 0,
    totalTokens: 0,
    totalCost: 0,
    contextWindowSize: 200000,
  })

  const [viewSessionPath, setViewSessionPathState] = useState<string | null>(null)
  const [runtimeSessionPath, setRuntimeSessionPathState] = useState<string | null>(null)
  const [runtimeSessionId, setRuntimeSessionId] = useState<string | null>(null)
  const [softSwitchBackgroundAgentEnded, setSoftSwitchBackgroundAgentEnded] = useState(false)
  const backgroundEventBuffer = useRef<AgentSessionEvent[]>([])

  // Refs for values used in handleEvent to avoid stale closures
  const viewSessionPathRef = useRef<string | null>(null)
  const runtimeSessionPathRef = useRef<string | null>(null)
  const runtimeSessionIdRef = useRef<string | null>(null)

  // State setters that also update refs immediately (for closure safety)
  const setViewSessionPath = useCallback((path: string | null) => {
    viewSessionPathRef.current = path
    setViewSessionPathState(path)
  }, [])

  const setRuntimeSessionPath = useCallback((path: string | null) => {
    runtimeSessionPathRef.current = path
    setRuntimeSessionPathState(path)
  }, [])

  // Also keep runtimeSessionIdRef in sync (no custom setter for this one)
  runtimeSessionIdRef.current = runtimeSessionId

  // Soft-switch state: derived from viewSessionPath + runtimeSessionPath.
  // We keep a ref for handleEvent closure safety (avoids stale closure over state).
  const isSoftSwitchedRef = useRef(false)
  const isSoftSwitchedDerived = viewSessionPath !== null && runtimeSessionPath !== null && viewSessionPath !== runtimeSessionPath
  isSoftSwitchedRef.current = isSoftSwitchedDerived
  const isSoftSwitched = isSoftSwitchedDerived

  const currentAssistantId = useRef<string | null>(null)
  const currentContentBlocks = useRef<Map<number, ContentBlock>>(new Map())
  const toolCallArgsBuffer = useRef<Map<number, string>>(new Map())
  const pendingToolCallArgs = useRef<Map<string, Record<string, unknown>>>(new Map())

  const updateContentBlock = useCallback(
    (contentIndex: number, updater: (block: ContentBlock) => ContentBlock) => {
      const existing = currentContentBlocks.current.get(contentIndex)
      if (existing) {
        currentContentBlocks.current.set(contentIndex, updater(existing))
      }
    },
    [],
  )

  // RAF-throttled sync to avoid flickering on every text_delta
  const rafIdRef = useRef<number | null>(null)
  const syncContentBlocksToMessage = useCallback(() => {
    if (!currentAssistantId.current) return
    // Always schedule at most one RAF frame
    if (rafIdRef.current !== null) return
    rafIdRef.current = requestAnimationFrame(() => {
      rafIdRef.current = null
      if (!currentAssistantId.current) return
      const blocks = Array.from(currentContentBlocks.current.values())
      const assistantId = currentAssistantId.current
      setMessages((prev) =>
        prev.map((msg) => {
          if (msg.id !== assistantId) return msg
          return { ...msg, blocks: [...blocks] }
        }),
      )
    })
  }, [])

  // Force-flush any pending RAF sync (used at message/agent end)
  const flushSync = useCallback(() => {
    if (rafIdRef.current !== null) {
      cancelAnimationFrame(rafIdRef.current)
      rafIdRef.current = null
    }
    if (!currentAssistantId.current) return
    const blocks = Array.from(currentContentBlocks.current.values())
    const assistantId = currentAssistantId.current
    setMessages((prev) =>
      prev.map((msg) => {
        if (msg.id !== assistantId) return msg
        return { ...msg, blocks: [...blocks] }
      }),
    )
  }, [])

  const finalizeCurrentAssistant = useCallback(() => {
    if (!currentAssistantId.current) return
    flushSync()
  }, [flushSync])

  // Wrapped setIsStreaming that also tracks ref and activity timestamp
  const updateStreamingState = useCallback((value: boolean) => {
    isStreamingRef.current = value
    if (value) {
      lastStreamingActivityRef.current = Date.now()
    }
    setIsStreaming(value)
  }, [])

  // Streaming safety watchdog: if isStreaming has been true for too long
  // without any content activity, auto-reset to false.
  useEffect(() => {
    if (!isStreaming) return
    const interval = setInterval(() => {
      if (isStreamingRef.current && Date.now() - lastStreamingActivityRef.current > STREAMING_TIMEOUT_MS) {
        console.warn('[usePiRpc] Streaming safety timeout - resetting isStreaming to false')
        isStreamingRef.current = false
        setIsStreaming(false)
      }
    }, 10_000)
    return () => clearInterval(interval)
  }, [isStreaming])

  // Track streaming activity (any content update resets the watchdog)
  const touchStreamingActivity = useCallback(() => {
    if (isStreamingRef.current) {
      lastStreamingActivityRef.current = Date.now()
    }
  }, [])

  const handleEvent = useCallback(
    (event: AgentSessionEvent) => {
      if (isSoftSwitchedRef.current) {
        const eventSessionId = (event as Record<string, unknown>).sessionId as string | undefined
        if (eventSessionId === runtimeSessionIdRef.current) {
          if (backgroundEventBuffer.current.length < 500) {
            backgroundEventBuffer.current.push(event)
          }
          if (event.type === 'agent_end') {
            backgroundEventBuffer.current = []
            updateStreamingState(false)
            setSoftSwitchBackgroundAgentEnded(true)
          }
        }
        return
      }

      switch (event.type) {
        case 'agent_start':
          updateStreamingState(true)
          break

        case 'agent_end':
          updateStreamingState(false)
          flushSync()
          currentAssistantId.current = null
          currentContentBlocks.current.clear()
          toolCallArgsBuffer.current.clear()
          onAgentEndRef.current?.()
          break

        case 'message_start': {
          const msg = event.message
          if (msg.role === 'user') {
            const userMsg = msg as PiUserMessage
            const userContent =
              typeof userMsg.content === 'string'
                ? userMsg.content
                : userMsg.content
                    .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                    .map((c) => c.text)
                    .join('')

            const userChatMsg: ChatMessage = {
              id: crypto.randomUUID(),
              role: 'user',
              blocks: [{ type: 'text', content: userContent }],
              timestamp: userMsg.timestamp,
            }
            setMessages((prev) => [...prev, userChatMsg])
          } else if (msg.role === 'assistant') {
            if (currentAssistantId.current) {
              // Reuse existing placeholder created by syncStreamingState (§6.6.2 Rule 3).
              // The placeholder already has the correct id and is in the messages array.
              // Just update its timestamp — content will be filled by message_update events.
              const existingId = currentAssistantId.current
              setMessages((prev) =>
                prev.map((m) =>
                  m.id === existingId
                    ? { ...m, timestamp: (msg as PiAssistantMessage).timestamp }
                    : m,
                ),
              )
            } else {
              const assistantMsg = msg as PiAssistantMessage
              const assistantId = crypto.randomUUID()
              currentAssistantId.current = assistantId
              currentContentBlocks.current.clear()
              toolCallArgsBuffer.current.clear()

              const chatMsg: ChatMessage = {
                id: assistantId,
                role: 'assistant',
                blocks: [],
                timestamp: assistantMsg.timestamp,
              }
              setMessages((prev) => [...prev, chatMsg])
            }
          }
          break
        }

        case 'message_update': {
          const updateEvent = event as MessageUpdateEvent
          const ame = updateEvent.assistantMessageEvent

          if (!currentAssistantId.current) break

          switch (ame.type) {
            case 'text_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '' })
              break

            case 'text_delta':
              touchStreamingActivity()
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'text_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content }
                }
                return block
              })
              break

            case 'thinking_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '💭 ' })
              break

            case 'thinking_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'thinking_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: '💭 ' + ame.content }
                }
                return block
              })
              break

            case 'toolcall_start':
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: '',
                args: {},
                status: 'running',
              })
              toolCallArgsBuffer.current.set(ame.contentIndex, '')
              break

            case 'toolcall_delta': {
              touchStreamingActivity()
              const existing = toolCallArgsBuffer.current.get(ame.contentIndex) ?? ''
              toolCallArgsBuffer.current.set(ame.contentIndex, existing + ame.delta)
              break
            }

            case 'toolcall_end': {
              const argsStr = toolCallArgsBuffer.current.get(ame.contentIndex) ?? '{}'
              let parsedArgs: Record<string, unknown>
              try {
                parsedArgs = JSON.parse(argsStr)
              } catch {
                parsedArgs = { _raw: argsStr }
              }
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: ame.toolCall.name,
                args: parsedArgs,
                status: 'running',
              })
              pendingToolCallArgs.current.set(ame.toolCall.id, parsedArgs)
              toolCallArgsBuffer.current.delete(ame.contentIndex)
              // toolcall_end is an important structural change, flush immediately
              flushSync()
              break
            }

            case 'done': {
              const msg = ame.message
              if (msg.usage) {
                setTokenUsage({
                  inputTokens: msg.usage.input,
                  outputTokens: msg.usage.output,
                  cacheReadTokens: msg.usage.cacheRead,
                  cacheWriteTokens: msg.usage.cacheWrite,
                  totalTokens: msg.usage.input + msg.usage.output,
                  totalCost: msg.usage.cost.total,
                  contextWindowSize: inferContextWindow(msg.responseModel),
                })
              }
              break
            }
            case 'error':
              break
          }

          if (ame.type !== 'toolcall_end') {
            syncContentBlocksToMessage()
          }
          break
        }

        case 'message_end': {
          const msg = event.message
          if (msg.role === 'toolResult') {
            const toolResultMsg = msg as PiToolResultMessage
            const extraBlocks: ContentBlock[] = []

            for (const content of toolResultMsg.content) {
              if (content.type === 'text') {
                extraBlocks.push({ type: 'text', content: content.text })
              } else if (content.type === 'image') {
                const img = content as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: 'Screenshot',
                })
              }
            }

            if (extraBlocks.length > 0 && currentAssistantId.current) {
              setMessages((prev) =>
                prev.map((m) => {
                  if (m.id !== currentAssistantId.current) return m
                  return { ...m, blocks: [...m.blocks, ...extraBlocks] }
                }),
              )
            }
          }
          if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            if (assistantMsg.usage) {
              setTokenUsage({
                inputTokens: assistantMsg.usage.input,
                outputTokens: assistantMsg.usage.output,
                cacheReadTokens: assistantMsg.usage.cacheRead,
                cacheWriteTokens: assistantMsg.usage.cacheWrite,
                totalTokens: assistantMsg.usage.input + assistantMsg.usage.output,
                totalCost: assistantMsg.usage.cost.total,
                contextWindowSize: inferContextWindow(assistantMsg.responseModel),
              })
            }
          }
          break
        }

        case 'tool_execution_start':
          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              return {
                ...msg,
                blocks: msg.blocks.map((block) => {
                  if (
                    block.type === 'tool_call' &&
                    block.toolName === event.toolName &&
                    block.status === 'pending'
                  ) {
                    return { ...block, status: 'running' as const }
                  }
                  return block
                }),
              }
            }),
          )
          break

        case 'tool_execution_end': {
          const toolEvent = event as ToolExecutionEndEvent
          const toolArgs = pendingToolCallArgs.current.get(toolEvent.toolCallId)
          pendingToolCallArgs.current.delete(toolEvent.toolCallId)

          const extraBlocks: ContentBlock[] = []

          const hasImageContent = toolEvent.result?.content?.some(
            (c: Record<string, unknown>) => c.type === 'image'
          )

          if (hasImageContent) {
            for (const c of toolEvent.result.content as Array<Record<string, unknown>>) {
              if (c.type === 'text' && typeof c.text === 'string') {
                extraBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as unknown as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${toolEvent.toolName}`,
                })
              }
            }
          }

          if (
            toolEvent.toolName === 'write' &&
            toolArgs &&
            typeof toolArgs.path === 'string' &&
            toolArgs.path.endsWith('.html') &&
            typeof toolArgs.content === 'string'
          ) {
            extraBlocks.push({
              type: 'html',
              content: toolArgs.content,
              title: toolArgs.path.split('/').pop(),
            })
          }

          if (extraBlocks.length > 0) {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: [
                    ...msg.blocks.map((block) => {
                      if (block.type === 'tool_call' && block.status === 'running') {
                        return { ...block, status: 'completed' as const }
                      }
                      return block
                    }),
                    ...extraBlocks,
                  ],
                }
              }),
            )
          } else {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: msg.blocks.map((block) => {
                    if (block.type === 'tool_call' && block.status === 'running') {
                      return { ...block, status: 'completed' as const }
                    }
                    return block
                  }),
                }
              }),
            )
          }
          break
        }

        default:
          break
      }
    },
    [updateContentBlock, syncContentBlocksToMessage, finalizeCurrentAssistant, updateStreamingState, touchStreamingActivity],
  )

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      setIsConnected(state.connected)
    })

    window.api.getState().then((state) => {
      setIsConnected(state.connected)
    })

    return cleanup
  }, [])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      handleEvent(rawEvent as AgentSessionEvent)
    })
    return cleanup
  }, [handleEvent])

  useEffect(() => {
    const cleanup = window.api.onExtensionUiRequest((data) => {
      const req = data as { id: string; method: string; [key: string]: unknown }
      if (req.method === 'notify') {
        return
      }
      if (req.method === 'setStatus' || req.method === 'setWidget' || req.method === 'setTitle' || req.method === 'set_editor_text') {
        return
      }
      setPendingUiRequests(prev => [...prev, req])
    })
    return cleanup
  }, [])

  const respondToUiRequest = useCallback((requestId: string, response: Record<string, unknown>) => {
    window.api.sendExtensionUIResponse({ type: 'extension_ui_response', id: requestId, ...response })
    setPendingUiRequests(prev => prev.filter(r => r.id !== requestId))
  }, [])

  const sendPrompt = useCallback(
    (text: string, images?: { data: string; mimeType: string }[]) => {
      const command: Record<string, unknown> = {
        type: 'prompt',
        message: text,
        id: crypto.randomUUID(),
      }
      if (images && images.length > 0) {
        command.images = images.map((img) => ({
          type: 'image' as const,
          data: img.data,
          mimeType: img.mimeType,
        }))
      }
      window.api.sendCommand(command)
    },
    [],
  )

  const abort = useCallback(() => {
    window.api.sendCommand({ type: 'abort' })
  }, [])

  const clearMessages = useCallback(() => {
    setMessages([])
    setForkPoints([])
    setTokenUsage({
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalTokens: 0,
      totalCost: 0,
      contextWindowSize: 200000,
    })
    setIsStreaming(false)
    isStreamingRef.current = false
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }, [])

  const enterSoftSwitch = useCallback(async (targetPath: string) => {
    type ApiWithSoftPeek = typeof window.api & { softPeek: (path: string) => Promise<{ messages: unknown[]; sessionId: string }> }
    const api = window.api as ApiWithSoftPeek

    let piMessages: unknown[]
    try {
      const result = await api.softPeek(targetPath)
      piMessages = result.messages
    } catch {
      piMessages = []
    }

    const chatMessages = convertPiMessagesToChatMessages(piMessages)

    // Update ref immediately so handleEvent starts filtering right away
    // (isSoftSwitched state is derived from viewSessionPath/runtimeSessionPath)
    isSoftSwitchedRef.current = true
    setViewSessionPath(targetPath)
    setMessages(chatMessages)
  }, [])

  const exitSoftSwitch = useCallback(async () => {
    const targetPath = runtimeSessionPathRef.current

    // Update ref immediately so handleEvent stops filtering right away
    // (isSoftSwitched state is derived from viewSessionPath/runtimeSessionPath)
    isSoftSwitchedRef.current = false

    type ApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    let piMessages: unknown[]
    try {
      piMessages = await (window.api as ApiWithMessages).getMessages()
    } catch {
      piMessages = []
    }

    const chatMessages = Array.isArray(piMessages) && piMessages.length > 0
      ? convertPiMessagesToChatMessages(piMessages)
      : []

    const lastAssistant = chatMessages.findLast(m => m.role === 'assistant')
    if (lastAssistant) {
      currentAssistantId.current = lastAssistant.id
      currentContentBlocks.current.clear()
      toolCallArgsBuffer.current.clear()
      pendingToolCallArgs.current.clear()
      lastAssistant.blocks.forEach((block, i) => {
        currentContentBlocks.current.set(i, block)
      })
    } else {
      currentAssistantId.current = null
      currentContentBlocks.current.clear()
      toolCallArgsBuffer.current.clear()
      pendingToolCallArgs.current.clear()
    }

    backgroundEventBuffer.current = []

    // Sync runtimeSessionId after switching back
    type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
    try {
      const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
      if (state.sessionId) {
        setRuntimeSessionId(state.sessionId)
      }
      // Update streaming state from runtime (agent may have ended while we were away)
      updateStreamingState(state.isStreaming)
    } catch {
      // Best effort
    }

    setMessages(chatMessages)
    setViewSessionPath(targetPath)
    setSoftSwitchBackgroundAgentEnded(false)
  }, [updateStreamingState])

  const hardSwitchToViewSession = useCallback(async () => {
    setSoftSwitchBackgroundAgentEnded(false)
    isSoftSwitchedRef.current = false
    const targetPath = viewSessionPathRef.current
    clearMessages()
    setRuntimeSessionPath(targetPath)
  }, [clearMessages])

  const [forkPoints, setForkPoints] = useState<ForkPoint[]>([])
  const onAgentEndRef = useRef<(() => void) | null>(null)

  const setOnAgentEnd = useCallback((cb: (() => void) | null) => {
    onAgentEndRef.current = cb
  }, [])

  const loadForkPoints = useCallback(async (sessionPath: string) => {
    type ExtendedApiWithForkPoints = typeof window.api & { getForkPoints: (path: string) => Promise<ForkPoint[]> }
    const apiWithFp = window.api as ExtendedApiWithForkPoints
    try {
      const points = await apiWithFp.getForkPoints(sessionPath)
      setForkPoints(points)
    } catch {
      setForkPoints([])
    }
  }, [])

  const loadHistory = useCallback(async () => {
    type ExtendedApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    const api = window.api as ExtendedApiWithMessages

    let piMessages: unknown[]
    try {
      piMessages = await api.getMessages()
    } catch {
      return
    }

    if (!Array.isArray(piMessages) || piMessages.length === 0) {
      clearMessages()
      return
    }

    const chatMessages = convertPiMessagesToChatMessages(piMessages)

    let restoredUsage: TokenUsage | null = null
    for (let i = piMessages.length - 1; i >= 0; i--) {
      const msg = piMessages[i] as Record<string, unknown>
      if (msg.role === 'assistant') {
        const usage = msg.usage as { input: number; output: number; cacheRead: number; cacheWrite: number; totalTokens: number; cost: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number } } | undefined
        const responseModel = typeof msg.responseModel === 'string' ? msg.responseModel : ''
        if (usage) {
          restoredUsage = {
            inputTokens: usage.input,
            outputTokens: usage.output,
            cacheReadTokens: usage.cacheRead,
            cacheWriteTokens: usage.cacheWrite,
            totalTokens: usage.input + usage.output,
            totalCost: usage.cost.total,
            contextWindowSize: inferContextWindow(responseModel),
          }
        }
        break
      }
    }

    clearMessages()
    setMessages(chatMessages)
    if (restoredUsage) {
      setTokenUsage(restoredUsage)
    }
    updateStreamingState(false)

    // Always sync runtime session info after loading history.
    // The null-checks on paths prevent overwriting values set by callers
    // (e.g., when hard-switching after background agent ends).
    type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
    try {
      const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
      setRuntimeSessionId(state.sessionId || null)
      if (state.sessionFile) {
        if (!viewSessionPathRef.current) setViewSessionPath(state.sessionFile)
        if (!runtimeSessionPathRef.current) setRuntimeSessionPath(state.sessionFile)
      }
    } catch {
      // Best effort
    }
  }, [clearMessages, updateStreamingState])

  const syncStreamingState = useCallback(async () => {
    try {
      type ApiWithRuntime = typeof window.api & { getRuntimeSessionId: () => Promise<{ sessionId: string; sessionFile: string; isStreaming: boolean }> }
      const state = await (window.api as ApiWithRuntime).getRuntimeSessionId()
      updateStreamingState(state.isStreaming)
      if (state.sessionFile) {
        setRuntimeSessionPath(state.sessionFile)
        if (!viewSessionPathRef.current) setViewSessionPath(state.sessionFile)
        setRuntimeSessionId(state.sessionId)
      }
      if (state.isStreaming && !currentAssistantId.current) {
        const placeholderId = crypto.randomUUID()
        currentAssistantId.current = placeholderId
        currentContentBlocks.current.clear()
        toolCallArgsBuffer.current.clear()
        setMessages((prev) => [
          ...prev,
          { id: placeholderId, role: 'assistant', blocks: [], timestamp: Date.now() },
        ])
      }
    } catch {
      updateStreamingState(false)
    }
  }, [updateStreamingState])

  const streamingMessageId = isStreaming ? currentAssistantId.current : null

  return { messages, isConnected, isStreaming, streamingMessageId, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, syncStreamingState, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd, tokenUsage, viewSessionPath, runtimeSessionPath, isSoftSwitched, enterSoftSwitch, exitSoftSwitch, hardSwitchToViewSession, setViewSessionPath, setRuntimeSessionPath, setRuntimeSessionId, softSwitchBackgroundAgentEnded }
}

